def select_neighbor(archive: List[Tuple[np.ndarray, Tuple[float, float]]], coords: np.ndarray, demand: np.ndarray, distance_matrix: np.ndarray, capacity: float) -> np.ndarray:
    total_distance = sum(obj[0] for _, obj in archive)
    total_makespan = sum(obj[1] for _, obj in archive)
    weights = [1 - (obj[0] / total_distance + obj[1] / total_makespan) / 2 for _, obj in archive]
    selected_index = random.choices(range(len(archive)), weights=weights)[0]
    selected_solution, _ = archive[selected_index]

    # Hybrid local search: merging routes
    new_routes = []
    current_route = []
    current_demand = 0

    for route in selected_solution:
        for customer in route[1:-1]:  # Skip depot (0)
            if current_demand + demand[customer] <= capacity:
                current_route.append(customer)
                current_demand += demand[customer]
            else:
                if current_route:
                    new_routes.append(np.array([0] + current_route + [0]))  # Add the completed route
                current_route = [customer]  # Start a new route
                current_demand = demand[customer]

    if current_route:
        new_routes.append(np.array([0] + current_route + [0]))  # Add the last route

    # Redistribute demand if necessary (simple heuristic)
    for i in range(len(new_routes)):
        if len(new_routes[i]) > 2:  # If the route has customers
            for j in range(len(new_routes)):
                if i != j and len(new_routes[j]) > 2:
                    combined_demand = sum(demand[customer] for customer in new_routes[i][1:-1])
                    if combined_demand + demand[new_routes[j][1]] <= capacity:
                        # Move the first customer of route j to route i
                        new_routes[i] = np.append(new_routes[i][:-1], new_routes[j][1])
                        new_routes[j] = np.delete(new_routes[j], 1)  # Remove customer from j
                        break

    return new_routes
